module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output reg yout,
    output reg done
);
    reg [4:0] i;
    reg [31:0] areg, breg, yout_r;
    reg done_r;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            i <= 5'd0;
            done_r <= 1'b0;
            areg <= 16'd0;
            breg <= 16'd0;
            yout_r <= 32'd0;
        end else begin
            if (start) begin
                if (i == 5'd0) begin
                    areg <= ain;
                    breg <= bin;
                end else if (i < 5'd17) begin
                    if (areg[i-1]) begin
                        yout_r <= yout_r + (breg << (i-1));
                    end
                end
            end

            if (i == 5'd16) begin
                done_r <= 1'b1;
            end else if (i == 5'd17) begin
                done_r <= 1'b0;
            end

            if (i < 5'd17) begin
                i <= i + 1;
            end else begin
                i <= 5'd0;
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            done <= 1'b0;
        end else begin
            done <= done_r;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            yout <= 32'd0;
        end else begin
            yout <= yout_r;
        end
    end
endmodule
